func TestValidateInstanceMetadata(t *testing.T) {
	cases := map[string]struct {
		Metadata      map[string]interface{}
		ExpectWarning string
	}{
		"with gce-container-declaration": {
			Metadata: map[string]interface{}{
				"gce-container-declaration": "some-value",
			},
			ExpectWarning: "The option to deploy a container during VM creation using the container startup agent is deprecated. Use alternative services to run containers on your VMs. Learn more at https://cloud.google.com/compute/docs/containers/migrate-containers.",
		},
		"without gce-container-declaration": {
			Metadata: map[string]interface{}{
				"foo": "bar",
			},
			ExpectWarning: "",
		},
		"with empty metadata": {
			Metadata:      map[string]interface{}{},
			ExpectWarning: "",
		},
	}

	for tn, tc := range cases {
		warnings, errs := tpgcompute.ValidateInstanceMetadata(tc.Metadata, "metadata")
		if len(errs) > 0 {
			t.Errorf("%s: Unexpected errors: %v", tn, errs)
		}
		if tc.ExpectWarning == "" {
			if len(warnings) > 0 {
				t.Errorf("%s: Expected no warning, got: %v", tn, warnings)
			}
		} else {
			if len(warnings) == 0 {
				t.Errorf("%s: Expected warning %q, got none", tn, tc.ExpectWarning)
			} else if warnings[0] != tc.ExpectWarning {
				t.Errorf("%s: Expected warning %q, got %q", tn, tc.ExpectWarning, warnings[0])
			}
		}
	}
}

func TestCheckForCommonAliasIp(t *testing.T) {
	type testCase struct {
		old, new []interface{}
		expected []interface{}
	}

	testCases := []testCase{
		{
			old: []interface{}{
				map[string]interface{}{"ipCidrRange": "10.0.0.0/24"},
				map[string]interface{}{"ipCidrRange": "10.0.1.0/24"},
			},
			new: []interface{}{
				map[string]interface{}{"ipCidrRange": "10.0.0.0/24"},
				map[string]interface{}{"ipCidrRange": "10.0.2.0/24"},
			},
			expected: []interface{}{
				map[string]interface{}{"ipCidrRange": "10.0.0.0/24"},
			},
		},
		{
			old: []interface{}{
				map[string]interface{}{"ipCidrRange": "172.16.0.0/24"},
				map[string]interface{}{"ipCidrRange": "10.0.1.0/24"},
			},
			new: []interface{}{
				map[string]interface{}{"ipCidrRange": "172.16.0.0/24"},
				map[string]interface{}{"ipCidrRange": "10.0.2.0/24"},
			},
			expected: []interface{}{
				map[string]interface{}{"ipCidrRange": "172.16.0.0/24"},
			},
		},
		{
			old: []interface{}{
				map[string]interface{}{"ipCidrRange": "10.0.0.0/24"},
				map[string]interface{}{"ipCidrRange": "10.0.1.0/24"},
			},
			new: []interface{}{
				map[string]interface{}{"ipCidrRange": "192.168.0.0/24"},
				map[string]interface{}{"ipCidrRange": "172.17.0.0/24"},
			},
			expected: []interface{}{},
		},
	}

	for _, tc := range testCases {
		oldInterface := map[string]interface{}{"aliasIpRanges": tc.old}
		newInterface := map[string]interface{}{"aliasIpRanges": tc.new}
		result := tpgcompute.CheckForCommonAliasIp(oldInterface, newInterface)
		assert.Equal(t, tc.expected, result)
	}
}

func computeInstanceImportStep(zone, instanceName string, additionalImportIgnores []string) resource.TestStep {
	// metadata is only read into state if set in the config
	// importing doesn't know whether metadata.startup_script vs metadata_startup_script is set in the config,
	// it always takes metadata.startup-script
	ignores := []string{"metadata.%", "metadata.startup-script", "metadata_startup_script", "boot_disk.0.initialize_params.0.resource_manager_tags.%", "params.0.resource_manager_tags.%"}

	return resource.TestStep{
		ResourceName:            "google_compute_instance.foobar",
		ImportState:             true,
		ImportStateId:           fmt.Sprintf("%s/%s/%s", envvar.GetTestProjectFromEnv(), zone, instanceName),
		ImportStateVerify:       true,
		ImportStateVerifyIgnore: append(ignores, additionalImportIgnores...),
	}
}

